import { expandableState } from '../../../expandable/expandable-parser';

function SetState() {
    let manager = this,
        { options } = manager,
        { legendInstance, markParser } = options,
        { expandable: expandableConfig } = legendInstance.meta.config.list,
        expanded = expandableState(markParser);

    expandableState(markParser, !expanded);
    expandableConfig._expanded = !expanded; // TODO: change
}

export { SetState };
